export type PrimeKeyFilter =
    | "pint" | "int" | "pnum" | "money" | "num" | "hex" | "email" | "alpha" | "alphanum"
    | RegExp;

const patterns: Record<string, RegExp> = {
    int: /^-?\d*$/,
    pint: /^\d*$/,
    num: /^-?\d*(\.\d*)?$/,
    pnum: /^\d*(\.\d*)?$/,
    money: /^\d*(\.\d{0,2})?$/,
    hex: /^[0-9a-fA-F]*$/,
    alpha: /^[A-Za-z]*$/,
    alphanum: /^[A-Za-z0-9]*$/,
    // “email” in Prime keyfilter is not full email validation; keep it permissive for typing.
    email: /^[A-Za-z0-9@._+-]*$/,
};

export function applyKeyFilter(next: string, keyFilter?: PrimeKeyFilter): string {
    if (!keyFilter) return next;

    const re =
        keyFilter instanceof RegExp
            ? keyFilter
            : patterns[keyFilter];

    if (!re) return next;

    return re.test(next) ? next : ""; // caller decides fallback strategy
}

/**
 * Safer: if next fails, keep previous.
 */
export function applyKeyFilterKeepPrev(prev: string, next: string, keyFilter?: PrimeKeyFilter): string {
    if (!keyFilter) return next;
    const re =
        keyFilter instanceof RegExp
            ? keyFilter
            : patterns[keyFilter];
    if (!re) return next;
    return re.test(next) ? next : prev;
}
